sudo bash -lc ' set -euo pipefail ADMIN_USER="admin2" ADMIN_PASS="改成你的强密码" export DATABASE_URL="$(sed -n "s/^DATABASE_URL=//p" /opt/dd-class/shared/.env.production | head -n1)" export SECRET_KEY="$(sed -n "s/^SECRET_KEY=//p" /opt/dd-class/shared/.env.production | head -n1)" cd /opt/dd-class/source /opt/dd-class/venv/bin/python - <<PY from app.database import SessionLocal from app.models import User from app.auth import get_password_hash username = "${ADMIN_USER}" password = "${ADMIN_PASS}" db = SessionLocal() try: user = db.query(User).filter(User.username == username).first() if user is None: user = User( username=username, hashed_password=get_password_hash(password), real_name="System Administrator", role="admin", is_active=True, ) db.add(user) db.commit() print(f"Created admin: {username}") else: user.hashed_password = get_password_hash(password) user.role = "admin" user.is_active = True db.add(user) db.commit() print(f"Updated admin: {username}") finally: db.close() PY '
